                    continue;
                }
                if (prop.NameEquals("redundancyMode"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    redundancyMode = prop.Value.GetString().ToRedundancyMode();
                    continue;
                }
                if (prop.NameEquals("inProgressOperationId"u8))
                {
                    inProgressOperationId = prop.Value.GetString();
                    continue;
                }
                if (prop.NameEquals("publicNetworkAccess"u8))
                {
                    publicNetworkAccess = prop.Value.GetString();
                    continue;
                }
                if (prop.NameEquals("storageAccountRequired"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    storageAccountRequired = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("keyVaultReferenceIdentity"u8))
                {
                    keyVaultReferenceIdentity = prop.Value.GetString();
                    continue;
                }
                if (prop.NameEquals("virtualNetworkSubnetId"u8))
                {
                    virtualNetworkSubnetId = prop.Value.GetString();
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new SitePatchResourceProperties(
                state,
                hostNames ?? new ChangeTrackingList<string>(),
                repositorySiteName,
                usageState,
                enabled,
                siteScopedCertificatesEnabled,
                enabledHostNames ?? new ChangeTrackingList<string>(),
                availabilityState,
                hostNameSslStates ?? new ChangeTrackingList<HostNameSslState>(),
                serverFarmId,
                reserved,
                isXenon,
                hyperV,
                lastModifiedTimeUtc,
                dnsConfiguration,
                siteConfig,
                aiIntegration,
                trafficManagerHostNames ?? new ChangeTrackingList<string>(),
                scmSiteAlsoStopped,
                targetSwapSlot,
                hostingEnvironmentProfile,
                clientAffinityEnabled,
                clientAffinityProxyEnabled,
                clientCertEnabled,
                clientCertMode,
                clientCertExclusionPaths,
                hostNamesDisabled,
                customDomainVerificationId,
                outboundIpAddresses,
                possibleOutboundIpAddresses,
                containerSize,
                dailyMemoryTimeQuota,
                suspendedTill,
                maxNumberOfWorkers,
                cloningInfo,
                resourceGroup,
                isDefaultContainer,
                defaultHostName,
                slotSwapStatus,
                httpsOnly,
                redundancyMode,
                inProgressOperationId,
                publicNetworkAccess,
                storageAccountRequired,
                keyVaultReferenceIdentity,
                virtualNetworkSubnetId,
                additionalBinaryDataProperties);
        }
    }
}
